import{c as a,b3 as r,aA as d,aD as e,z as h,a2 as b}from"./chunks/framework.C44IZsdK.js";const x=JSON.parse('{"title":"永生","description":"","frontmatter":{"order":4},"headers":[],"relativePath":"地图/弥天神域/永生.md","filePath":"地图/弥天神域/永生.md","lastUpdated":0}'),l={name:"地图/弥天神域/永生.md"};function o(i,t,n,s,c,m){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="永生" tabindex="-1">永生 <a class="header-anchor" href="#永生" aria-label="Permalink to “永生”">​</a></h1><h2 id="小怪掉落" tabindex="-1">小怪掉落 <a class="header-anchor" href="#小怪掉落" aria-label="Permalink to “小怪掉落”">​</a></h2><table tabindex="0"><thead><tr><th>材料</th></tr></thead><tbody><tr><td>永生玄晶</td></tr></tbody></table><h2 id="神域金木" tabindex="-1">神域金木 <a class="header-anchor" href="#神域金木" aria-label="Permalink to “神域金木”">​</a></h2><h3 id="达刹" tabindex="-1">达刹 <a class="header-anchor" href="#达刹" aria-label="Permalink to “达刹”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>金锥：宝座上的金锥闪动，达刹手轻轻一指，3根金锥轮流刺向玩家（若被命中3次，额外受到一次穿刺伤害）</td></tr><tr><td>金木：宝座上的金木触手依次伸出，抽打两侧的敌人</td></tr><tr><td>电球：达刹第3只眼发光闪动，在场上召唤出多个金色小光球，从空中一道道下落砸地</td></tr><tr><td>生命之源：在场景两侧召唤两团生命之源，为达刹输送生命，此时达刹无敌；存在期间，达刹每秒回复少量生命；生命之源充盈圆满时,飞入达刹体内，回复达刹大量生命</td></tr><tr><td>防护之源：在场景两侧召唤两团防护之源，为达刹输送防护，此时达刹无敌；存在期间，达刹每秒获得少额减伤；防护之源充盈圆满时,飞入达刹体内，达刹获得大额减伤</td></tr><tr><td>神之头颅：金光从头顶传输如小头中，召唤出元神头颅出现在场景中<br>头颅-神之眼：从眼中发射出一道金光<br>头颅-金影：朝斜下前方呼出一团金色气体，触碰到气体的人命中下降</td></tr><tr><td>神之藐视：整个王座发光一圈圈金光，达刹免疫减益状态，此时攻击王座会被晕眩</td></tr></tbody></table><table tabindex="0"><thead><tr><th>掉落材料</th><th>掉落装备</th></tr></thead><tbody><tr><td>永生莲叶</td><td>永生魂珏</td></tr></tbody></table><h2 id="永生泉" tabindex="-1">永生泉 <a class="header-anchor" href="#永生泉" aria-label="Permalink to “永生泉”">​</a></h2><h3 id="妙音天女" tabindex="-1">妙音天女 <a class="header-anchor" href="#妙音天女" aria-label="Permalink to “妙音天女”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>琴音：拨动琴弦，朝前方释放一道音波</td></tr><tr><td>天女心咒·水：持续弹奏凝聚水能力，控制地面多处泉水涌动，一小段时间后向上喷发（使敌人获得潮湿状态）</td></tr><tr><td>天女心咒·冰：拨动琴弦，朝前方释放出一道冰凤，并在沿路遗留多个小冰柱，小冰柱遗留一段时间，碰到会立刻爆炸（使敌人获得冰凝状态）</td></tr><tr><td>天女心咒·雷：持续蓄力，在场景生成多个音律球，一段时间后爆炸（使敌人获得雷引状态）</td></tr><tr><td>琴瑟和鸣：持续施法，在场景召唤水、冰、雷3把琵琶，琵琶同时响动，每隔一小段时间给天女输送生命，防御/魔抗，攻击（琴可被打破）</td></tr><tr><td>余音绕梁：给自身添加琴音护盾（被打使攻击者沉默）</td></tr><tr><td>被动技：当敌人身上存在2个状态时，触发额外效果；<br>潮湿状态+冰凝状态：冰冻<br>潮湿状态+雷引状态：麻痹，降低命中<br>冰凝状态+雷引状态：冰爆，造成伤害</td></tr></tbody></table><table tabindex="0"><thead><tr><th>掉落材料</th><th>掉落装备</th></tr></thead><tbody><tr><td>永生莲刺</td><td>永生魂锥</td></tr></tbody></table><h2 id="永生泉隐藏" tabindex="-1">永生泉隐藏 <a class="header-anchor" href="#永生泉隐藏" aria-label="Permalink to “永生泉隐藏”">​</a></h2><p>第一遍<strong>最后点亮</strong>紫色莲花，第二遍<strong>最后点亮</strong>蓝色莲花，然后在紫色莲花旁边可以找到<strong>隐藏入口</strong></p><img src="'+h+'" alt="永生泉隐藏" style="zoom:67%;"><h3 id="伐楼拿" tabindex="-1">伐楼拿 <a class="header-anchor" href="#伐楼拿" aria-label="Permalink to “伐楼拿”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>附体寒潮：伐楼拿的技能命中玩家时会施加潮湿状态，最高5层</td></tr><tr><td>爆裂水泡：海龟吐出水炮攻击，碰到敌人、墙壁或地板后爆炸消失</td></tr><tr><td>海兽之魂：丢出收水瓶（矮胖瓶身），收回玩家身上的潮湿状态并根据层数回复血量，切换海兽形态（轮换顺序：海蛇-&gt;海龟-&gt;海贼），每个形态持续20s<br>海蛇形态：攻击和暴击提高<br>海龟形态：防御和魔抗提高<br>海贼形态：闪避和回血提高</td></tr><tr><td>游蛇水弹：在地图角落有水炮汇集成海蛇的形状，朝玩家的方向攻击</td></tr><tr><td>水神护罩：获得保护罩，若玩家没有在护盾持续时间内打破护盾，护盾会爆炸造成伤害并沉默玩家，且伐楼拿会根据剩余护盾值回复血量</td></tr><tr><td>触手爪牙：召唤触手分身攻击玩家。触手可被击杀，每击杀一条触手反馈给本体一定伤害。此时伐楼拿进入无敌状态，直到玩家击杀5个触手</td></tr><tr><td>汪洋之泪：丢出泄水瓶于头顶，滴出一滴魔法水滴，落至地面后反弹成一颗水球。水球落至地面后再次分裂，直到分裂成5颗水球后引爆全屏</td></tr></tbody></table><table tabindex="0"><thead><tr><th>掉落材料</th><th>掉落装备</th></tr></thead><tbody><tr><td>永生莲蕊</td><td>永生魂环</td></tr></tbody></table><h2 id="云水镜" tabindex="-1">云水镜 <a class="header-anchor" href="#云水镜" aria-label="Permalink to “云水镜”">​</a></h2><h3 id="梵天" tabindex="-1">梵天 <a class="header-anchor" href="#梵天" aria-label="Permalink to “梵天”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>传经诵读：4个头随机诵读经传，诵读后会在敌人头顶召唤光圈，光圈出现一小段时间后向下释放光芒笼罩敌人，对敌人造成伤害<br>黄色：降低攻击<br>红色：降低魔抗<br>蓝色：降低命中<br>绿色：降低闪避</td></tr><tr><td>转轮念珠：转动手中念珠，8颗念珠从中心向外发射，造成伤害；8颗念珠每转动一圈提升梵天防御和魔抗，若转动3圈未清除所有念珠则收回念珠并获得大幅减伤效果</td></tr><tr><td>智识经书：召唤手中知识之书参与战斗，30s后复原<br>知识之书技能：对前方敌人释放能量，对敌人造成伤害并晕眩</td></tr><tr><td>圣水倾卸：分别向左右两侧泼洒圣水，对敌人造成伤害并沉默</td></tr><tr><td>流影莲光：手中莲花幻化作流光，环绕梵天运动，对敌人造成伤害</td></tr><tr><td>永生莲座：释放莲花座之力，此时攻击boss，boss会不断回复生命并反伤</td></tr></tbody></table><table tabindex="0"><thead><tr><th>掉落材料</th><th>掉落装备</th></tr></thead><tbody><tr><td>永生莲子</td><td>永生魂铃</td></tr></tbody></table><h2 id="法宝" tabindex="-1">法宝 <a class="header-anchor" href="#法宝" aria-label="Permalink to “法宝”">​</a></h2><h3 id="永生魂幢" tabindex="-1">永生魂幢 <a class="header-anchor" href="#永生魂幢" aria-label="Permalink to “永生魂幢”">​</a></h3><img src="'+b+'" alt="永生魂幢" style="zoom:50%;"><table tabindex="0"><thead><tr><th>被动</th><th>属性</th></tr></thead><tbody><tr><td>回血</td><td>17~23</td></tr><tr><td>回魔</td><td>10~14</td></tr></tbody></table>',25)])])}const y=a(l,[["render",o]]);export{x as __pageData,y as default};
